import React, { useState } from 'react';

const TabbedDashboardContent = () => {
  const [activeTab, setActiveTab] = useState('overview');

  const tabs = [
    { id: 'overview', name: 'Overview', content: 'This section provides a high-level summary of your most critical data points. Visualize key trends and overall performance at a glance. Drill down for more details.' },
    { id: 'performance', name: 'Performance', content: 'Dive deep into performance metrics. Analyze individual component performance, identify bottlenecks, and track efficiency over time. Custom charts and graphs available.' },
    { id: 'analytics', name: 'Analytics', content: 'Explore advanced analytics and predictive insights. Leverage machine learning models to forecast future trends and make data-driven decisions. Custom report builder included.' },
  ];

  return (
    <div className="mt-6 bg-white p-6 rounded-lg shadow-md border border-gray-100">
      <div className="border-b border-gray-200">
        <nav className="-mb-px flex space-x-4 sm:space-x-6" aria-label="Tabs">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`
                whitespace-nowrap py-2 px-3 sm:px-4 rounded-t-md text-sm font-medium
                ${activeTab === tab.id
                  ? 'border-b-2 border-zinc-500 text-zinc-900 focus:outline-none'
                  : 'text-zinc-600 hover:text-zinc-800 hover:bg-zinc-50 transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-inset focus:ring-zinc-200'
                }
              `}
              aria-current={activeTab === tab.id ? 'page' : undefined}
            >
              {tab.name}
            </button>
          ))}
        </nav>
      </div>

      <div className="py-6">
        {tabs.map((tab) => (
          <div key={tab.id} className={activeTab === tab.id ? 'block' : 'hidden'}>
            <h2 className="text-xl font-semibold text-zinc-800 mb-3">{tab.name} Data</h2>
            <p className="text-zinc-700 leading-relaxed">
              {tab.content}
            </p>
            {/* Placeholder for actual dashboard content */}
            <div className="mt-4 p-4 bg-zinc-50 border border-gray-100 rounded-md text-zinc-600 text-sm italic">
              <p>Placeholder for charts, graphs, and data tables related to {tab.name}.</p>
              <p className="mt-2">More interactive components would be rendered here based on selected tab.</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TabbedDashboardContent;

